import type { Exam } from '../domain/models/Exam';

export const EXAM_6: Exam = {
  title: "Mock Exam 6",
  subtitle: "Full-Length Simulation F — Edge Cases & Emerging Tech",
  sections: [
    // SCENARIO 1 – AI system transitioning between risk levels (D1/D3/D4)
    { type: "scenario", scenario: "NovaMed develops a wellness chatbot that provides general health tips based on publicly available guidelines. Originally classified as minimal risk under the EU AI Act, the product team proposes an upgrade: the chatbot will now analyze user-reported symptoms, access electronic health records via API integration, and provide preliminary diagnostic suggestions before a physician consultation. The medical advisory board warns that the upgrade fundamentally changes the system's risk profile. The AIMS team must reassess the entire governance framework. Meanwhile, the original risk assessment, SoA, and operational controls were designed for a minimal-risk system. The AI policy makes no reference to high-risk AI system requirements.", questions: [
      { question: "The chatbot transitions from providing general health tips to preliminary diagnostic suggestions. Under the EU AI Act, how does the risk classification change?", options: ["It remains minimal risk because the chatbot only provides suggestions, not definitive diagnoses", "It transitions to high-risk because AI systems intended to be used as a safety component or as a medical device fall under high-risk classification when they influence diagnostic decisions", "It becomes limited risk, requiring only transparency that users are interacting with AI"], correct: 1, explanation: "When an AI system moves from general information to influencing diagnostic decisions and accessing health records, it enters the high-risk category under the EU AI Act's classification of AI systems used in healthcare contexts." },
      { question: "The existing risk assessment was designed for a minimal-risk system. What is the most appropriate AIMS response to the system upgrade?", options: ["Add an addendum to the existing risk assessment noting the upgrade, as the core system architecture remains unchanged", "Conduct a comprehensive new AI risk assessment (Clause 8.2) for the upgraded system, as the fundamental change in functionality and risk profile renders the previous assessment inadequate for identifying new risks", "Postpone the risk assessment until after the upgrade is deployed to assess risks based on actual operational data"], correct: 1, explanation: "A fundamental change in system functionality and risk profile requires a comprehensive new risk assessment. The previous assessment's scope and criteria were calibrated for a minimal-risk system and cannot adequately address high-risk considerations." },
      { question: "The SoA was developed for a minimal-risk system and excludes controls related to human oversight and transparency. What must happen?", options: ["The existing SoA remains valid because the control exclusions were justified at the time of initial assessment", "The SoA must be revised to reassess the applicability of all Annex A controls against the new risk profile, with previously excluded controls such as human oversight and enhanced transparency likely requiring inclusion and justification", "Only the controls specifically mandated by the EU AI Act need to be added to the SoA"], correct: 1, explanation: "A significant change in risk profile necessitates a complete SoA review. Controls previously excluded as unnecessary for a minimal-risk system may now be essential for a high-risk system, and all exclusions must be re-justified." },
      { question: "The AI policy makes no reference to high-risk AI system requirements. What action is needed?", options: ["The AI policy is a high-level document and does not need to reference specific risk categories", "The AI policy should be reviewed and updated to ensure it provides an appropriate framework for setting objectives and managing AI systems across different risk levels, including commitments relevant to high-risk AI governance", "A separate policy document should be created specifically for high-risk AI systems"], correct: 1, explanation: "Clause 5.2 requires the AI policy to be appropriate to the organization's purpose and provide a framework for objectives. When the organization's AI activities expand to include high-risk systems, the policy should reflect this expanded scope." },
      { question: "The medical advisory board warns that the upgrade fundamentally changes the system's risk profile. Under Clause 8.4, what is required?", options: ["An AI system impact assessment evaluating potential consequences of the upgraded system on individuals, including patients who may rely on preliminary diagnostic suggestions for health decisions", "Only a technical performance assessment comparing accuracy metrics between the old and new system versions", "Impact assessment is only required after deployment, not during the planning phase"], correct: 0, explanation: "Clause 8.4 requires AI system impact assessment. When a system upgrade fundamentally changes its potential impact on individuals, an impact assessment must evaluate consequences before deployment, not after." }
    ]},

    // SCENARIO 2 – Mature vs. immature AIMS in a joint venture (D3/D4/D5)
    { type: "scenario", scenario: "TechGiant (holding ISO/IEC 42001 certification for three years with a mature AIMS) forms a joint venture with StartupAI (no formal AI governance) to develop AI-powered financial fraud detection. The joint venture will combine TechGiant's governance framework with StartupAI's innovative ML algorithms. TechGiant's AIMS manager insists on applying their full governance framework to the joint venture. StartupAI's CTO argues this will stifle innovation and slow development. The joint venture must process sensitive financial data from banks in four countries and deploy models that make automated decisions affecting customer accounts. Key staff from both organizations will work in blended teams, creating challenges for competence standards and awareness requirements.", questions: [
      { question: "TechGiant insists on applying their full governance framework to the joint venture. StartupAI argues it will stifle innovation. What is the most appropriate AIMS approach?", options: ["Apply TechGiant's entire framework without modification, as it has proven effective over three years", "Develop a proportionate governance framework for the joint venture based on its own context analysis (Clause 4.1/4.2), risk profile, and operational needs, leveraging TechGiant's mature practices where appropriate while adapting to the venture's specific requirements", "Adopt StartupAI's agile approach initially and add governance incrementally as the venture matures"], correct: 1, explanation: "Each organization must determine its own AIMS based on its context. The joint venture is a new entity with its own risk profile and must develop governance proportionate to its needs, not simply copy another organization's framework or defer governance." },
      { question: "Blended teams from both organizations have vastly different levels of AI governance awareness. How should Clause 7.3 awareness requirements be addressed?", options: ["Only TechGiant staff need awareness training since they are accountable for governance compliance", "All personnel working within the joint venture's AIMS scope must be made aware of the AI policy, their contribution to AIMS effectiveness, and implications of not conforming, regardless of their originating organization", "StartupAI staff should complete TechGiant's full three-year training curriculum before beginning work"], correct: 1, explanation: "Clause 7.3 requires all persons doing work under the organization's control to be aware of the AI policy, their contribution, and non-conformity implications. This applies to all joint venture staff regardless of their background or originating organization." },
      { question: "StartupAI's ML algorithms were developed without documented data provenance or model validation records. What must the joint venture address before deployment?", options: ["Document the algorithms retroactively based on developer recollection, as the models have proven effective in testing", "Establish data governance controls including data provenance documentation, conduct formal model validation, and create documented evidence of the system's development lifecycle before integrating these algorithms into the joint venture's AIMS", "Accept StartupAI's internal testing results as sufficient evidence, supplemented by TechGiant's governance stamp of approval"], correct: 1, explanation: "Annex A data governance controls and documented information requirements (Clause 7.5) require proper documentation of data provenance and model validation. Retroactive documentation from memory and informal test results do not satisfy these requirements." },
      { question: "The joint venture processes financial data from banks in four countries. How should the AIMS address multi-jurisdictional data governance?", options: ["Apply the data governance requirements of the strictest jurisdiction uniformly across all operations", "Identify data governance requirements from each jurisdiction as external issues (Clause 4.1) and interested-party requirements (Clause 4.2), map them to AIMS controls, and implement jurisdiction-specific controls where requirements differ", "Delegate data governance to each country's local bank partner since they hold the data"], correct: 1, explanation: "Different jurisdictions may have overlapping and distinct requirements. The AIMS should identify and map these through context analysis, implementing controls that satisfy each jurisdiction's requirements rather than assuming the strictest covers all or delegating responsibility." },
      { question: "TechGiant's AIMS manager proposes that the joint venture's initial management review replicate TechGiant's review format and agenda. Is this appropriate?", options: ["Yes, TechGiant's proven format ensures a rigorous first management review", "The management review should be structured to address the joint venture's specific context, including Clause 9.3 required inputs relevant to the venture's unique risks, operational status, and the integration challenges of combining two organizational cultures", "No, the joint venture should not conduct a management review until it has been operational for at least twelve months"], correct: 1, explanation: "Clause 9.3 requires management review inputs specific to the organization. While TechGiant's format can inform the approach, the joint venture's review must address its own context, risks, and challenges rather than simply replicating another organization's template." }
    ]},

    // SCENARIO 3 – Merger/acquisition with conflicting AI governance (D3/D4/D6)
    { type: "scenario", scenario: "GlobalBank (ISO/IEC 42001 certified) acquires FinAI Corp, a company with thirty AI systems used for trading, risk analysis, and customer profiling. FinAI Corp has no formal AIMS but operates under a self-developed 'Responsible AI Framework.' Post-acquisition, GlobalBank must integrate FinAI Corp's AI systems into its certified AIMS. The integration team discovers that several of FinAI Corp's trading AI systems operate with minimal human oversight, the risk analysis AI uses data from sources that have not been vetted for quality, and the customer profiling system applies different fairness criteria than GlobalBank's certified systems. GlobalBank's next surveillance audit is in four months.", questions: [
      { question: "GlobalBank must integrate FinAI Corp's thirty AI systems into its certified AIMS before the surveillance audit in four months. What is the most prudent approach?", options: ["Immediately extend the AIMS scope to include all thirty systems and implement all required controls before the surveillance audit", "Prioritize a risk-based integration plan: conduct initial risk assessment of all systems, immediately address the highest-risk gaps, formally extend the AIMS scope with a realistic timeline, and communicate the integration plan transparently to the certification body", "Exclude FinAI Corp's systems from the AIMS scope until after the surveillance audit to avoid audit complications"], correct: 1, explanation: "A risk-based, phased approach is most prudent. Attempting full integration in four months risks incomplete controls, while excluding systems entirely could mislead about the organization's actual AI operations. Transparent communication with the certification body is essential." },
      { question: "FinAI Corp's trading AI systems operate with minimal human oversight. Under GlobalBank's AIMS, what assessment must be conducted?", options: ["No assessment is needed if the trading systems have demonstrated consistent profitability, as financial performance validates the adequacy of current oversight levels", "An AI system impact assessment (Clause 8.4) evaluating the potential consequences of autonomous trading decisions, combined with a risk assessment to determine whether current oversight levels are appropriate given GlobalBank's risk criteria and regulatory requirements", "Only a regulatory compliance check against financial trading regulations, as human oversight requirements come from regulators rather than ISO/IEC 42001"], correct: 1, explanation: "Impact assessment and risk assessment are both required. Autonomous trading decisions carry significant financial and market impact that must be evaluated. Oversight levels must be assessed against the organization's own risk criteria and applicable regulations." },
      { question: "The risk analysis AI uses data from unvetted sources. What is the certification risk for GlobalBank's existing AIMS?", options: ["No certification risk, as the unvetted data sources only affect FinAI Corp's systems which are not yet in scope", "If GlobalBank extends its AIMS scope to include these systems, unvetted data sources represent a nonconformity against data governance controls; if not addressed, this could result in findings during the surveillance audit that affect the existing certification", "The certification body cannot assess data governance for systems acquired through merger"], correct: 1, explanation: "Including systems with unvetted data sources in the AIMS scope creates conformity risks. Even before formal scope extension, the certification body may question whether GlobalBank is managing all its AI operations responsibly under the AIMS principles." },
      { question: "FinAI Corp's customer profiling uses different fairness criteria than GlobalBank. How should this be harmonized?", options: ["Apply GlobalBank's fairness criteria uniformly to all systems immediately, as the acquiring organization's standards take precedence", "Evaluate both sets of criteria against the organization's AI policy, regulatory requirements, and interested-party expectations; develop harmonized criteria that satisfy all applicable requirements, documenting the rationale for the chosen approach", "Maintain separate fairness criteria for legacy FinAI Corp systems to avoid disrupting their established performance benchmarks"], correct: 1, explanation: "Harmonization should be driven by policy requirements, regulations, and stakeholder expectations rather than simply defaulting to either organization's existing approach. The rationale must be documented and the chosen criteria must satisfy all applicable requirements." },
      { question: "FinAI Corp operated under a self-developed 'Responsible AI Framework.' How should this be treated during AIMS integration?", options: ["Discard it entirely since it was not based on ISO/IEC 42001 and may embed non-conforming practices", "Conduct a gap analysis comparing the framework against ISO/IEC 42001 requirements, retaining controls and practices that satisfy AIMS requirements and adding or modifying elements where gaps exist", "Accept it as an equivalent to ISO/IEC 42001 since it demonstrates organizational commitment to responsible AI"], correct: 1, explanation: "A gap analysis identifies overlaps and gaps between the existing framework and ISO/IEC 42001. Effective practices should be retained and enhanced rather than discarded, while gaps must be addressed to achieve conformity." }
    ]},

    // SCENARIO 4 – Regulatory change scenario (D1/D3)
    { type: "scenario", scenario: "DataServe operates AI-powered public services in the European Union, including benefits eligibility assessment, social housing allocation, and public transportation optimization. A new amendment to the EU AI Act reclassifies AI systems used in public service access decisions from high-risk to a stricter sub-category requiring enhanced conformity assessment, mandatory third-party audits of algorithms, and real-time monitoring by a national AI authority. The organization has six months to comply. Their current AIMS was designed to meet the original high-risk requirements. The AI policy references the EU AI Act but does not include a mechanism for adapting to regulatory changes. Two of the three AI systems use deep learning models that are difficult to explain, and the national AI authority has indicated it will require detailed technical explanations of decision logic.", questions: [
      { question: "The EU AI Act amendment introduces stricter requirements for public service AI systems. How should this regulatory change enter the AIMS?", options: ["Through the next scheduled annual risk review, as regulatory changes follow the standard review cycle", "Immediately through Clause 4.1 as a change in external issues and Clause 4.2 as a change in interested-party requirements, triggering risk assessment updates and review of the SoA and operational controls", "Through Clause 10.2 continual improvement, as regulatory adaptation is an improvement activity"], correct: 1, explanation: "Regulatory changes are external issues (4.1) and interested-party requirements (4.2) that must be addressed promptly. They trigger cascading updates through risk assessment, SoA review, and operational control adjustments." },
      { question: "The AI policy references the EU AI Act but has no mechanism for adapting to regulatory changes. What AIMS improvement is needed?", options: ["The AI policy does not need a regulatory adaptation mechanism; regulatory monitoring is an operational activity", "The AIMS should establish a regulatory monitoring and change management process that identifies upcoming regulatory changes, assesses their impact on the AIMS, and triggers timely updates to policy, controls, and procedures", "The AI policy should list specific regulatory requirements rather than referencing frameworks, so changes are immediately visible"], correct: 1, explanation: "A proactive regulatory monitoring process ensures the organization identifies and responds to regulatory changes in a timely manner. This supports both the AIMS's responsiveness and Clause 6.3's requirement for planned changes." },
      { question: "The national AI authority requires detailed technical explanations of decision logic, but two systems use deep learning models that are difficult to explain. How should this tension be addressed?", options: ["Inform the national authority that deep learning models cannot be explained and request an exemption", "Implement explainability techniques appropriate to the model types (such as SHAP values, attention visualization, or surrogate models), document the limitations of explainability, and engage with the authority to determine acceptable explanation methods", "Replace the deep learning models with rule-based systems that are inherently explainable, regardless of accuracy impact"], correct: 1, explanation: "The organization should employ available explainability techniques, transparently document limitations, and engage with the regulator to establish acceptable approaches. Neither requesting exemptions nor sacrificing system effectiveness is proportionate." },
      { question: "Mandatory third-party algorithm audits are now required. How does this interact with the existing AIMS internal audit program?", options: ["Third-party algorithm audits replace the need for internal audits of those systems", "Third-party algorithm audits are a regulatory requirement that should be integrated into the AIMS audit framework, complementing but not replacing internal audits under Clause 9.2, which serve different purposes", "Internal audits should be suspended until the third-party audit methodology is established to avoid conflicting findings"], correct: 1, explanation: "Third-party regulatory audits and internal AIMS audits serve different purposes. Regulatory audits assess algorithm compliance; internal audits assess AIMS conformity. Both are needed and should be coordinated within the AIMS audit framework." },
      { question: "The organization has six months to comply with the new requirements. The AIMS manager proposes a phased compliance approach. What should be the first priority?", options: ["Implementing real-time monitoring infrastructure for the national AI authority, as this is the most technically complex requirement", "Conducting a comprehensive gap analysis between current AIMS controls and the new regulatory requirements, prioritizing gaps based on risk and establishing a realistic implementation plan with defined milestones", "Updating all documented information to reference the new amendment before making any operational changes"], correct: 1, explanation: "A gap analysis establishes the baseline and enables informed prioritization. Without understanding the full scope of gaps, the organization cannot effectively allocate resources or sequence implementation activities." }
    ]},

    // SCENARIO 5 – Emerging AI technology governance (D1/D4)
    { type: "scenario", scenario: "SynthLabs is a research organization that has developed a foundation model capable of generating synthetic data, code, and scientific hypotheses. The model is being commercialized through an API offered to pharmaceutical companies for drug discovery, financial institutions for risk modeling, and government agencies for policy simulation. The organization's AIMS was originally designed for narrow AI systems with well-defined inputs and outputs. The foundation model exhibits emergent capabilities that were not anticipated during development, including the ability to generate plausible but factually incorrect scientific claims. One pharmaceutical client reports that researchers are using the model's outputs without independent verification, and a government agency client discovers the model produces different policy recommendations for identical inputs depending on prompt phrasing.", questions: [
      { question: "The foundation model exhibits emergent capabilities not anticipated during development. How should the AIMS address this?", options: ["Emergent capabilities are a positive feature that demonstrates model sophistication and should be documented as an asset rather than a risk", "The AI risk assessment must be updated to identify emergent capabilities as potential sources of uncontrolled behavior, evaluate risks associated with unanticipated outputs, and establish monitoring for detecting new emergent behaviors over time", "Emergent capabilities should be disabled through model constraints to ensure outputs remain within the originally designed parameters"], correct: 1, explanation: "Emergent capabilities represent unknown and potentially uncontrolled behaviors. The AIMS must treat these as risks requiring assessment, monitoring, and appropriate controls, as they may produce harmful or unreliable outputs." },
      { question: "Researchers at a pharmaceutical client use model outputs without independent verification. What AIMS responsibility does SynthLabs have?", options: ["None, as the client's internal verification processes are outside SynthLabs' control and AIMS scope", "SynthLabs should address this through communication controls (Clause 7.4) and user documentation, clearly communicating the model's limitations, intended use, and the necessity of independent verification as part of its operational controls for the AI system", "SynthLabs should implement technical controls that prevent the model from being used for drug discovery applications"], correct: 1, explanation: "While SynthLabs cannot control client behavior, it has AIMS responsibilities for communicating system limitations, defining intended use parameters, and providing guidance on appropriate use. This falls under communication and operational controls." },
      { question: "The model produces different policy recommendations for identical inputs depending on prompt phrasing. What AI-specific risk does this represent?", options: ["This is normal behavior for generative AI and does not constitute a risk requiring treatment", "This represents a robustness and reliability risk: inconsistent outputs for semantically equivalent inputs undermine trust and may lead to different decisions based on arbitrary prompt variations rather than substantive differences", "This risk is the responsibility of the government agency client to manage through prompt engineering training"], correct: 1, explanation: "Output inconsistency for equivalent inputs is a robustness concern that affects system reliability and trustworthiness. Under AI risk management, this must be identified, assessed, and treated through appropriate technical and procedural controls." },
      { question: "The AIMS was designed for narrow AI systems with well-defined inputs and outputs. What structural adaptation is needed for the foundation model?", options: ["No adaptation is needed; the AIMS framework is technology-agnostic and applies equally to narrow and foundation models", "The risk assessment methodology, impact assessment scope, operational controls, and monitoring framework must be adapted to account for the foundation model's broader capability envelope, multi-purpose nature, and downstream use across different domains and risk levels", "Only the SoA needs updating to add controls specific to foundation models"], correct: 1, explanation: "Foundation models differ fundamentally from narrow AI in their scope, capability, and risk profile. Multiple AIMS elements need adaptation, not just the SoA. The risk assessment methodology, monitoring approach, and operational controls all require revision." },
      { question: "The model generates plausible but factually incorrect scientific claims. Which Annex A control area is most critical?", options: ["Controls related to AI system documentation, ensuring all model outputs are recorded with timestamps", "Controls related to AI system reliability and accuracy, including output validation mechanisms, user communication about limitations, and monitoring for hallucination or confabulation patterns", "Controls related to information security, preventing unauthorized access to the model's knowledge base"], correct: 1, explanation: "Generating plausible but incorrect information (confabulation/hallucination) is a core reliability and accuracy concern. Controls must address output validation, user communication about this limitation, and monitoring for patterns of incorrect outputs." }
    ]},

    // SCENARIO 6 – Organizations with very different AI maturity levels seeking certification (D6/D3)
    { type: "scenario", scenario: "Two organizations simultaneously apply for ISO/IEC 42001 certification through the same certification body. Organization A is a large enterprise with twenty AI systems, a dedicated AI governance team of fifteen people, three years of operational data, and a mature risk management framework. Organization B is a small company with two AI systems, one part-time governance coordinator, six months of operational data, and basic risk management. The certification body must apply consistent audit criteria while recognizing different organizational contexts. During Stage 1, Organization A's documentation is comprehensive but overly complex, with staff unable to explain the governance procedures they are supposed to follow. Organization B's documentation is minimal but every staff member clearly understands their AI governance responsibilities.", questions: [
      { question: "Organization A has comprehensive documentation but staff cannot explain governance procedures. Organization B has minimal documentation but high staff understanding. Which organization better satisfies Clause 7.3 awareness requirements?", options: ["Organization A, because comprehensive documentation demonstrates a superior awareness program", "Organization B better demonstrates Clause 7.3 compliance because awareness requires that persons are actually aware of the AI policy and their contribution to AIMS effectiveness, not merely that documentation exists describing the awareness program", "Neither organization satisfies Clause 7.3 because both comprehensive documentation and staff understanding are independently required"], correct: 1, explanation: "Clause 7.3 requires actual awareness among personnel, not just documented awareness programs. Organization B demonstrates that staff understand their roles, while Organization A's documentation without understanding indicates an awareness program failure." },
      { question: "The certification body must apply consistent criteria to both organizations despite their different sizes and maturity levels. How should ISO/IEC 42001 requirements be evaluated?", options: ["Apply identical audit criteria regardless of organizational size, as ISO/IEC 42001 requirements are absolute and do not vary", "Evaluate both organizations against the same ISO/IEC 42001 requirements, but recognize that the standard allows for proportionate implementation based on organizational context, complexity, and risk profile", "Apply simplified criteria to Organization B since it is smaller and cannot be expected to meet the same standards as a large enterprise"], correct: 1, explanation: "ISO/IEC 42001 requirements apply to all organizations, but the standard recognizes that implementation can be proportionate to context and complexity. The certification body evaluates conformity to requirements, not equivalence of implementation approach." },
      { question: "Organization A has three years of operational data demonstrating AIMS effectiveness. Organization B has only six months. How should the certification body assess evidence of effective implementation?", options: ["Organization B cannot be certified because six months is insufficient to demonstrate AIMS effectiveness", "Six months can be sufficient if the organization can demonstrate that its AIMS processes are implemented and operating effectively, including at least one complete cycle of internal audit and management review, though the evidence base will naturally be smaller", "Both organizations need a minimum of twelve months of operational data before Stage 2 can be conducted"], correct: 1, explanation: "There is no fixed minimum operational period in ISO/IEC 42001. The certification body evaluates whether there is sufficient evidence of implementation effectiveness, including completion of essential management system cycles. Six months can suffice for a smaller, less complex organization." },
      { question: "Organization A's documentation is overly complex. During Stage 1, the auditor should address this how?", options: ["Document complexity is not an audit concern as long as all required documented information exists", "Note that while documented information requirements (Clause 7.5) are met in terms of existence, the complexity may undermine the AIMS's effectiveness by creating a gap between documented procedures and actual practice, recommending simplification", "Require Organization A to reduce documentation to match Organization B's level before proceeding to Stage 2"], correct: 1, explanation: "Overly complex documentation that staff cannot follow undermines AIMS effectiveness. While the auditor cannot prescribe documentation volume, they can identify that the gap between documentation and practice may indicate effectiveness concerns." },
      { question: "Organization B has one part-time governance coordinator fulfilling multiple AIMS roles. Is this arrangement conforming under Clause 5.3?", options: ["No, ISO/IEC 42001 requires a full-time dedicated AIMS manager", "Yes, provided the coordinator has sufficient time, competence, and authority to fulfill the assigned responsibilities, and there are no conflicts of interest between the multiple roles", "Only if the coordinator has formal AI governance certification"], correct: 1, explanation: "Clause 5.3 requires that roles are assigned and have appropriate authority, but does not mandate full-time positions. A part-time coordinator can be sufficient if they have adequate time, competence, authority, and no conflicting responsibilities." }
    ]},

    // SCENARIO 7 – AI system decommissioning and end-of-life (D4/D3)
    { type: "scenario", scenario: "RetailMax is decommissioning its legacy AI-powered inventory prediction system after five years of operation. The system will be replaced by a new vendor's solution. The decommissioning plan includes turning off the system, deleting the training data, archiving the model artifacts, and notifying warehouse managers. However, the AIMS team discovers that the legacy system's training data includes personal purchase history that is subject to data retention regulations, the model was involved in two unresolved customer complaints about pricing fairness, the new vendor's system has not yet undergone AI risk assessment or impact assessment, and three downstream systems depend on the legacy AI's output format. The operations team wants to switch systems over a weekend to minimize business disruption.", questions: [
      { question: "The legacy system's training data includes personal purchase history subject to retention regulations. What AIMS consideration applies to data deletion?", options: ["Delete all training data immediately upon decommissioning to minimize data protection risk", "The data retention policy must comply with applicable legal requirements; deletion must be evaluated against regulatory retention obligations, and the AIMS must document the data handling decision with justification", "Training data retention is not an AIMS concern; it falls under data protection policies managed separately"], correct: 1, explanation: "Data governance controls within the AIMS must account for regulatory retention requirements. Immediate deletion may violate retention obligations, while indefinite retention may violate data minimization principles. The decision must be documented and justified." },
      { question: "Two unresolved customer complaints relate to the legacy system's pricing fairness. What must happen before decommissioning?", options: ["The complaints can be archived with the system since they relate to the legacy system, not the new one", "The complaints must be resolved through the corrective action process (Clause 10.1) regardless of system decommissioning, as the organization's obligation to address nonconformities is not extinguished by retiring the system that caused them", "Transfer the complaints to the new vendor as part of the system replacement agreement"], correct: 1, explanation: "Corrective action obligations under Clause 10.1 are not tied to a specific system's operational status. Unresolved complaints indicating potential nonconformities must be addressed through the AIMS corrective action process regardless of system decommissioning." },
      { question: "The new vendor's system has not undergone AI risk assessment or impact assessment. What must occur before deployment?", options: ["Deploy the new system and conduct assessments during the first month of operation when real data is available", "Conduct AI risk assessment (Clause 8.2) and AI system impact assessment (Clause 8.4) before deploying the new system, updating the SoA and implementing appropriate controls before the system goes live", "Accept the vendor's own risk assessment as sufficient since they developed the system"], correct: 1, explanation: "Clause 8.2 and 8.4 require risk and impact assessment before operational deployment. The organization cannot deploy a new AI system within its AIMS scope without first completing these assessments and implementing necessary controls." },
      { question: "Three downstream systems depend on the legacy AI's output format. The operations team wants to switch systems over a weekend. What AIMS requirement is most relevant?", options: ["Clause 7.4 communication, requiring notification to all affected parties before the switch", "Clause 8.1 operational planning and control, requiring assessment of change impacts on dependent systems, implementation of transition controls, fallback procedures, and validation that downstream systems function correctly with the new format", "Clause 6.3 planning of changes, which only requires documenting the planned switch date"], correct: 1, explanation: "Clause 8.1 requires operational control of changes. A system switch affecting downstream dependencies needs impact assessment, transition planning, fallback procedures, and validation, not just stakeholder notification or scheduling documentation." },
      { question: "The decommissioning plan should include which AI lifecycle consideration that is often overlooked?", options: ["Calculation of return on investment over the system's operational lifetime", "Preservation of sufficient documentation, model artifacts, and audit trails to support post-decommissioning inquiries, regulatory investigations, or lessons learned, as well as controlled removal of the system from the AIMS scope with SoA updates", "Transfer of the AI development team to the new vendor to maintain system knowledge continuity"], correct: 1, explanation: "AI system decommissioning is part of the AI lifecycle. The AIMS must ensure documentation preservation for accountability, update the SoA and scope, and maintain records that support future inquiries or investigations." }
    ]},

    // SCENARIO 8 – Cross-border AI deployment and cultural challenges (D3/D4)
    { type: "scenario", scenario: "HireRight deploys an AI-powered resume screening system across offices in the United States, Saudi Arabia, Germany, and India. The system was trained on hiring data from US operations. The German works council demands co-determination rights over the AI system's deployment criteria. Saudi Arabia's labor regulations require different candidate evaluation criteria than those in the US. India's data protection law imposes data localization requirements. The US-trained model shows performance disparities across cultural contexts—for example, it penalizes non-linear career paths that are common in certain cultures. The organization's AIMS was developed at US headquarters with minimal input from international offices.", questions: [
      { question: "The German works council demands co-determination rights over AI deployment criteria. How should the AIMS address this?", options: ["Works council requirements are labor relations matters outside the AIMS scope", "The works council is an interested party under Clause 4.2 whose requirements regarding AI system deployment must be identified and addressed through the AIMS, potentially including review and approval rights over screening criteria", "Acknowledge the works council's concerns in the stakeholder register but proceed with deployment as planned"], correct: 1, explanation: "Clause 4.2 requires identifying interested parties and their requirements. Works councils with co-determination rights represent interested parties whose requirements have legal force and must be addressed through the AIMS." },
      { question: "The AI model penalizes non-linear career paths common in certain cultures. What AIMS processes should address this?", options: ["No action needed if the penalization is consistent across all applicants, as the system treats everyone equally based on the same criteria", "AI risk assessment (Clause 8.2) to identify cultural bias as a risk, AI system impact assessment (Clause 8.4) to evaluate discriminatory effects across populations, and risk treatment to implement fairness controls including training data diversification and bias testing", "Add a disclaimer to the system output stating that results may vary across cultural contexts"], correct: 1, explanation: "Consistent application of culturally biased criteria still produces discriminatory outcomes. The AIMS must identify this as a risk, assess the impact on affected populations, and implement treatment measures to address the bias." },
      { question: "India's data localization requirements mean candidate data cannot be processed outside India. What AIMS control is most directly affected?", options: ["Clause 7.5 documented information, requiring documentation of data localization compliance", "Data governance controls and operational controls (Clause 8.1) governing where and how AI processing occurs, potentially requiring local deployment or processing infrastructure and changes to the system architecture", "Clause 7.4 communication, requiring the organization to inform Indian candidates about data localization"], correct: 1, explanation: "Data localization affects where AI processing occurs, which is an operational control matter. The organization may need to deploy local processing infrastructure, modify its AI architecture, or adjust data flows to comply." },
      { question: "Saudi Arabia requires different candidate evaluation criteria than the US. How should the AIMS handle jurisdiction-specific AI configuration?", options: ["Use the same evaluation criteria globally to ensure consistency and fairness across all operations", "Implement jurisdiction-specific AI configurations as part of operational controls (Clause 8.1), with each configuration assessed through the risk assessment process and documented in the SoA with justification for jurisdiction-specific variations", "Create separate AIMS for each jurisdiction to manage different requirements independently"], correct: 1, explanation: "Different jurisdictions may have legitimate reasons for different evaluation criteria. The AIMS should manage jurisdiction-specific configurations through operational controls, with each variation risk-assessed and documented." },
      { question: "The AIMS was developed at US headquarters with minimal international input. What Clause 4.1 and 4.2 deficiency does this represent?", options: ["No deficiency, as headquarters is the appropriate location for developing organizational governance frameworks", "The context analysis and interested-party identification may be incomplete, failing to capture external issues, cultural factors, and stakeholder requirements specific to non-US operations, resulting in an AIMS that does not adequately address the organization's full operating environment", "The deficiency is in Clause 5.1 leadership, not in context analysis, as international offices should have been consulted as a leadership decision"], correct: 1, explanation: "Clause 4.1 and 4.2 require comprehensive identification of internal and external issues and interested parties. Developing the AIMS without international input likely missed jurisdiction-specific issues, cultural factors, and stakeholder requirements." }
    ]},

    // SCENARIO 9 – Surveillance audit edge cases (D5/D6)
    { type: "scenario", scenario: "CyberShield holds ISO/IEC 42001 certification and is due for its second surveillance audit. Since the first surveillance audit, the organization has outsourced its entire AI development function to a third-party provider, reduced its internal AI team from twenty to three people (retained only for vendor management), changed its certification scope to exclude two decommissioned AI systems but has not formally notified the certification body, and experienced a data breach that exposed training data for its flagship AI system. The internal audit conducted two months ago was performed by the remaining three-person team, all of whom report to the same manager. The management review was conducted by the IT Director alone because the CEO considers the AIMS 'a compliance checkbox now that certification is achieved.'", questions: [
      { question: "CyberShield outsourced its entire AI development function. What impact does this have on AIMS responsibilities?", options: ["AIMS responsibilities transfer to the outsourcing provider, reducing CyberShield's obligations proportionally", "The organization retains full AIMS responsibility; outsourcing requires enhanced third-party management controls, contractual governance requirements, and monitoring of the outsourced function to ensure continued conformity", "The AIMS scope should be reduced to exclude development activities since they are no longer performed in-house"], correct: 1, explanation: "Outsourcing does not transfer AIMS responsibility. The organization must implement controls for third-party management, establish contractual governance requirements, and monitor the outsourced function. Scope reduction for outsourced activities is not appropriate." },
      { question: "The certification scope was changed to exclude decommissioned systems without notifying the certification body. What issue does this create?", options: ["No issue; organizations can adjust their scope independently between surveillance audits", "Significant changes to the certified scope must be communicated to the certification body; unilateral scope changes without notification may invalidate the certification or result in nonconformities during surveillance", "The certification body only needs notification if systems are added to scope, not removed"], correct: 1, explanation: "Changes to the certified scope, including reductions, must be communicated to the certification body. Unilateral changes undermine the validity of the certificate, which represents the scope as certified." },
      { question: "The internal audit was conducted by three people who all report to the same manager. What audit quality concern exists?", options: ["No concern, as three auditors provide sufficient team coverage", "Auditor objectivity and impartiality are compromised: Clause 9.2 requires auditors to ensure objectivity and impartiality, and auditing processes managed by one's own reporting line creates a structural bias that undermines audit credibility", "The concern is only about competence, not impartiality, since all three are AI professionals"], correct: 1, explanation: "Clause 9.2 requires objectivity and impartiality. When all auditors report to the same manager, there is a structural conflict of interest, particularly if they are auditing processes under that manager's responsibility." },
      { question: "The CEO considers the AIMS a 'compliance checkbox' and the management review was conducted by the IT Director alone. What non-conformities are present?", options: ["Only a Clause 9.3 nonconformity for inadequate management review participation", "Multiple nonconformities: Clause 5.1 requires top management to demonstrate leadership and commitment to the AIMS; Clause 9.3 requires management review by top management including evaluation of AIMS effectiveness, not delegation to a single director", "The IT Director can conduct management review on behalf of the CEO through delegation"], correct: 1, explanation: "Clause 5.1 requires top management to demonstrate leadership and commitment. Treating the AIMS as a checkbox violates leadership requirements. Clause 9.3 requires top management to conduct management review, which cannot be fully delegated." },
      { question: "A data breach exposed training data for the flagship AI system. What cascading AIMS actions are required?", options: ["Only information security incident response is needed, as data breaches are outside ISO/IEC 42001 scope", "The organization must evaluate the breach as a nonconformity (Clause 10.1), assess whether exposed training data affects AI system integrity and security (Clause 8.2), update the risk assessment, determine whether the AI system's outputs may be compromised, and report to relevant authorities as required", "Document the breach in the next management review and include it in the risk register for future reference"], correct: 1, explanation: "A training data breach has AIMS implications beyond information security. It may compromise AI system integrity, require risk reassessment, potentially affect model trustworthiness, and trigger regulatory reporting. Multiple AIMS processes must be activated." }
    ]},

    // SCENARIO 10 – Recertification and continual improvement assessment (D6/D5)
    { type: "scenario", scenario: "AIHealth is preparing for its three-year recertification audit. Over the certification cycle, the organization has expanded from two AI systems to twelve, entered three new markets, and experienced two significant AI incidents (a misdiagnosis that led to delayed treatment and a data leak of patient information). The recertification audit team includes a new lead auditor who has never audited AIHealth before. During the recertification audit, the team finds that while the organization has grown significantly, the AIMS resources have remained constant—the same two-person governance team manages twelve systems. The corrective action log shows that root causes for both incidents were identified as 'human error' with corrective actions limited to retraining the individuals involved. The continual improvement register contains only items from internal audit findings and no proactive improvements.", questions: [
      { question: "AIHealth expanded from two to twelve AI systems with the same two-person governance team. What should the recertification auditor evaluate?", options: ["Whether the team has maintained adequate documentation for all twelve systems", "Whether the organization has adequate resources (Clause 7.1) to maintain AIMS effectiveness across the expanded scope, and whether resource constraints have led to control gaps or reduced governance quality", "Whether the two-person team holds current professional certifications in AI governance"], correct: 1, explanation: "Clause 7.1 requires the organization to determine and provide resources needed for the AIMS. A six-fold increase in AI systems without corresponding resource increase raises serious questions about whether the AIMS can be effectively maintained." },
      { question: "Both AI incidents were attributed to 'human error' with corrective actions limited to retraining individuals. What should the auditor assess?", options: ["Whether the individuals completed their retraining and whether their performance improved", "Whether the root cause analysis was adequate: attributing incidents to 'human error' without investigating systemic factors such as process design, system controls, resource adequacy, and organizational culture suggests superficial root cause analysis that fails Clause 10.1 requirements", "Whether the incidents were properly documented and reported to the relevant authorities"], correct: 1, explanation: "Clause 10.1 requires determining the cause of nonconformities. Attributing complex AI incidents to 'human error' without exploring systemic factors (process gaps, control failures, resource constraints) indicates inadequate root cause analysis." },
      { question: "The continual improvement register contains only items from internal audit findings. What does this indicate about Clause 10.2 implementation?", options: ["The organization has fully implemented Clause 10.2 because it is acting on all internal audit findings", "Continual improvement is reactive rather than proactive: Clause 10.2 requires improving AIMS suitability, adequacy, and effectiveness, which should include proactive improvements from monitoring trends, technology changes, lessons learned, and management review outputs", "Internal audit findings are the only valid source of improvement items under ISO/IEC 42001"], correct: 1, explanation: "Clause 10.2 encompasses proactive improvement, not just reactive responses to findings. A mature AIMS should generate improvement initiatives from multiple sources including trend analysis, technology evolution, and strategic direction." },
      { question: "The recertification audit team includes a lead auditor who has never audited AIHealth before. Is this advantageous or problematic?", options: ["Problematic, because unfamiliarity with the organization reduces audit efficiency and effectiveness", "Advantageous from an impartiality perspective: a new lead auditor brings fresh eyes without familiarity bias, though they must review previous audit history and understand the organization's context to conduct an effective audit", "Neither advantageous nor problematic; auditor rotation has no impact on audit quality"], correct: 1, explanation: "Auditor rotation reduces familiarity threats to impartiality. A new lead auditor provides objectivity, though they must adequately prepare by reviewing the organization's history and context to maintain audit effectiveness." },
      { question: "The recertification audit evaluates the AIMS over the entire three-year cycle. What distinguishes this from a surveillance audit?", options: ["Recertification audits only review changes made since the last surveillance audit", "Recertification evaluates the effectiveness of the management system in its entirety over the certification cycle, including continued relevance and applicability of the scope, while surveillance audits sample selected areas of the AIMS", "Recertification audits are shorter than surveillance audits since the AIMS has already been proven effective"], correct: 1, explanation: "Recertification evaluates the entire AIMS's continued effectiveness and scope relevance over the full certification cycle, while surveillance audits examine selected areas. Recertification is more comprehensive, not less." }
    ]},

    // STANDALONE QUESTIONS (30 questions)
    { type: "standalone", questions: [
      // Domain 1 – Fundamentals (7 more to reach 17 total with scenarios)
      { question: "A neural network achieves state-of-the-art performance but operates as a 'black box' with no interpretable decision pathway. According to ISO/IEC TR 24028, what aspect of trustworthiness is most directly compromised?", options: ["Robustness, because black-box models are inherently less stable than transparent models", "Transparency, as the inability to understand and examine AI system behavior directly undermines stakeholders' ability to assess and trust the system's decisions", "Safety, because uninterpretable models cannot be verified as safe for deployment"], correct: 1, explanation: "ISO/IEC TR 24028 identifies transparency as a key trustworthiness characteristic. Black-box behavior directly compromises the ability of stakeholders to understand, examine, and trust AI decision-making." },
      { question: "Under the EU AI Act, a company develops an AI system that generates deepfake videos. What risk classification applies to this system?", options: ["Unacceptable risk, as all deepfake generation tools are prohibited", "Limited risk, requiring transparency obligations such as clearly disclosing that the content has been artificially generated or manipulated", "Minimal risk, as creative content generation has no specific regulatory requirements"], correct: 1, explanation: "AI systems generating deepfakes fall under limited risk in the EU AI Act, requiring transparency obligations to inform viewers that content has been artificially generated. They are not prohibited outright unless used for specific harmful purposes." },
      { question: "The NIST AI RMF 'Measure' function includes which critical activity?", options: ["Measuring the return on investment of AI projects to justify continued funding", "Employing quantitative and qualitative methods to analyze, assess, benchmark, and monitor AI risk and related impacts, using appropriate metrics and methodologies", "Measuring team productivity in AI development sprints"], correct: 1, explanation: "The Measure function focuses on employing methods to analyze, assess, benchmark, and monitor AI risk and impacts. It is about risk measurement and impact assessment, not financial or productivity metrics." },
      { question: "ISO/IEC 22989 distinguishes between 'AI system' and 'AI model.' What is the key difference?", options: ["An AI model is a theoretical concept while an AI system is a physical implementation", "An AI model is the algorithmic component that performs inference or learning, while an AI system is the engineered system that incorporates one or more AI models along with other components to accomplish defined objectives", "An AI system contains exactly one AI model, while multiple AI models combined form an AI platform"], correct: 1, explanation: "ISO/IEC 22989 defines the AI model as the algorithmic component and the AI system as the broader engineered system incorporating models along with other components like data pipelines, interfaces, and infrastructure." },
      { question: "According to ISO/IEC 23894, what distinguishes AI risk management from general enterprise risk management?", options: ["AI risk management uses entirely different methodologies incompatible with enterprise risk management frameworks", "AI systems introduce unique risk characteristics including opacity, data dependency, emergent behavior, and potential for societal-scale impact that require specialized consideration within the broader risk management framework", "AI risk management only applies to organizations with more than fifty AI systems"], correct: 1, explanation: "ISO/IEC 23894 recognizes that AI introduces unique risk characteristics that require specialized consideration, while being integrated within, not separate from, the organization's broader risk management approach." },
      { question: "Under the EU AI Act, what obligations does a 'deployer' of high-risk AI systems have compared to a 'provider'?", options: ["Deployers have no obligations; all compliance responsibilities rest with the provider", "Deployers must use the system in accordance with provider instructions, monitor system performance, maintain logs, conduct fundamental rights impact assessments for certain uses, and report incidents, while providers bear design and conformity assessment responsibilities", "Deployers and providers share identical obligations under the EU AI Act"], correct: 1, explanation: "The EU AI Act distinguishes provider and deployer obligations. Deployers have specific responsibilities including proper use, monitoring, logging, impact assessment for certain categories, and incident reporting, while providers handle design-time compliance." },
      { question: "ISO/IEC 42005 provides guidance on AI system impact assessment. What types of impacts does it address?", options: ["Only financial impacts on the organization deploying the AI system", "Impacts on individuals, groups, communities, and society, including effects on fundamental rights, economic impacts, environmental impacts, and effects on democratic processes", "Only technical performance impacts such as accuracy, latency, and availability"], correct: 1, explanation: "ISO/IEC 42005 addresses a broad range of impacts beyond financial or technical metrics, encompassing effects on individuals, communities, society, fundamental rights, economic and environmental impacts." },

      // Domain 2 – AIMS requirements (5 questions)
      { question: "ISO/IEC 42001 requires the organization to determine the scope of the AIMS as documented information. What level of specificity is expected?", options: ["A brief statement such as 'all AI systems' is sufficient", "The scope statement must identify the boundaries and applicability of the AIMS, including the AI systems covered, organizational units, locations, and any exclusions with justification", "The scope only needs to identify the number of AI systems and the department responsible"], correct: 1, explanation: "Clause 4.3 requires a scope statement that clearly defines boundaries and applicability, providing enough specificity to understand what is and is not covered by the AIMS, including justification for any exclusions." },
      { question: "How does the Plan-Do-Check-Act cycle manifest in ISO/IEC 42001's clause structure?", options: ["ISO/IEC 42001 follows a linear implementation sequence rather than a cyclical PDCA model", "Plan maps to Clauses 4-6 (context, leadership, planning), Do to Clauses 7-8 (support, operation), Check to Clause 9 (performance evaluation), and Act to Clause 10 (improvement), creating a continuous improvement cycle", "PDCA is only referenced in the introduction and has no structural relationship to the clauses"], correct: 1, explanation: "The Harmonized Structure embeds PDCA: planning clauses (4-6) establish the Plan, support and operation (7-8) represent Do, performance evaluation (9) is Check, and improvement (10) is Act, creating a continuous cycle." },
      { question: "An auditor reviews ISO/IEC 42001 Clause 8.3 on AI risk treatment. What distinguishes AI risk treatment from general risk treatment?", options: ["AI risk treatment uses the same four options (mitigate, transfer, avoid, accept) as general risk management with no distinctions", "AI risk treatment must consider AI-specific control measures from Annex A, the dynamic nature of AI risks that may change as models evolve, and the potential for AI risk treatment to introduce new risks such as fairness-accuracy tradeoffs", "AI risk treatment eliminates the option of risk acceptance since all AI risks must be mitigated"], correct: 1, explanation: "While the fundamental treatment options are similar, AI risk treatment must account for AI-specific controls, the evolving nature of AI risks, and the possibility that treating one AI risk may create or exacerbate others, requiring iterative assessment." },
      { question: "What role does Annex D play in an organization's ISO/IEC 42001 implementation?", options: ["Annex D contains mandatory controls that must be implemented by all certified organizations", "Annex D provides an informative catalog of potential sources of AI-related risk, helping organizations identify risks they might otherwise overlook during their AI risk assessment process", "Annex D provides the template format for the Statement of Applicability"], correct: 1, explanation: "Annex D is informative (not mandatory) and catalogs potential AI-related risk sources. It supports the risk assessment process by helping organizations identify risks comprehensively, serving as a reference rather than a checklist." },
      { question: "An organization claims its AIMS is compliant because it addresses all ten clauses (1-10) of ISO/IEC 42001. Why might this claim be insufficient?", options: ["Clauses 1 through 3 are introductory and are not auditable requirements, so claiming compliance with them is meaningless", "Compliance with main body clauses alone is insufficient; the organization must also determine and implement applicable Annex A controls as referenced by the main clauses, documented in a Statement of Applicability", "Clauses 4 through 10 contain optional requirements that are only mandatory if the organization chooses to include them in scope"], correct: 1, explanation: "ISO/IEC 42001 requires not only conformity with main body clauses but also selection and implementation of applicable Annex A controls, documented in the SoA. Addressing only the main clauses without Annex A implementation is incomplete." },

      // Domain 3 – Planning (5 more to reach 20 with scenarios)
      { question: "An organization identifies 'rapid advancement of AI technology' as an external issue under Clause 4.1. How should this translate into AIMS planning?", options: ["Document the issue in the context analysis and review it annually", "Incorporate it into the risk assessment as a source of both risk (technology obsolescence, emerging threat vectors) and opportunity (capability enhancement, competitive advantage), establishing monitoring mechanisms for technology trends that may affect the AIMS", "This is too vague to be actionable and should be replaced with specific technology references"], correct: 1, explanation: "External issues identified under Clause 4.1 should feed into risk assessment and planning. Technology advancement represents both risks and opportunities that require ongoing monitoring and periodic reassessment." },
      { question: "An organization's AI risk assessment identifies a risk of model hallucination in a customer-facing chatbot. The risk owner proposes accepting the risk because the probability of harmful hallucination is low. What must be verified before acceptance?", options: ["Only that the risk owner has sufficient authority to accept risks", "That risk acceptance criteria have been defined, the proposed acceptance falls within those criteria, the potential impact on interested parties has been considered, acceptance is documented with justification, and the decision is approved at an appropriate management level", "That the chatbot includes a disclaimer stating it may produce inaccurate responses"], correct: 1, explanation: "Risk acceptance requires defined criteria, impact consideration, documented justification, and appropriate management approval. A disclaimer is a communication control, not a substitute for proper risk acceptance governance." },
      { question: "During scope definition, the organization excludes an AI system used for employee monitoring from the AIMS scope, citing that it is an HR tool. An interested party (employee union) objects. How should this be resolved?", options: ["The organization has sole authority over scope decisions and can disregard the union's objection", "The objection should be evaluated under Clause 4.2 by assessing whether the employee union's requirements regarding AI governance of monitoring systems are relevant requirements that should be addressed through the AIMS", "Include the system in scope only if the union has legal standing to compel inclusion"], correct: 1, explanation: "Clause 4.2 requires identifying interested parties and their relevant requirements. Employee unions with legitimate concerns about AI monitoring are relevant interested parties whose requirements should be evaluated, not dismissed." },
      { question: "An organization establishes AI objectives including 'achieve 99% accuracy on all AI models within 12 months.' What is problematic about this objective?", options: ["Nothing; it is specific, measurable, and time-bound as Clause 6.2 requires", "A single accuracy target across all AI models ignores that different systems serve different purposes with different acceptable performance levels; objectives should be tailored to each system's context, intended use, and risk profile", "The 12-month timeframe is too aggressive for accuracy improvement targets"], correct: 1, explanation: "Clause 6.2 requires objectives at relevant functions and levels. A blanket accuracy target ignores that different AI systems have different performance requirements based on their purpose, risk level, and affected populations." },
      { question: "An organization's AI policy commits to 'compliance with all applicable AI regulations.' During an audit, the auditor discovers the organization has not identified which specific regulations apply. Is the policy conforming?", options: ["Yes, the commitment to comply with applicable regulations satisfies Clause 5.2", "The policy statement itself may satisfy Clause 5.2, but the failure to identify applicable regulations indicates a non-conformity in Clause 4.1 (external issues) and Clause 4.2 (interested-party requirements), undermining the policy commitment", "No, the AI policy must explicitly list each applicable regulation by name and section"], correct: 1, explanation: "While the policy commitment satisfies 5.2, the organization must actually identify applicable regulations through 4.1 and 4.2 analysis. A generic commitment without identification of specific applicable requirements cannot be effectively implemented." },

      // Domain 4 – Implementation (3 more to reach 18 with scenarios)
      { question: "An organization's AIMS requires documented information to be approved before use. AI-generated documentation (model cards, test reports) is automatically produced by the ML pipeline. How should approval be handled?", options: ["Automated generation constitutes implicit approval since the pipeline was approved during implementation", "The organization must define approval processes for AI-generated documentation, which may include automated validation checks combined with human review at appropriate stages, ensuring that Clause 7.5 requirements for adequacy and suitability are met", "AI-generated documentation does not require approval since it is a system output, not a human-authored document"], correct: 1, explanation: "Clause 7.5 requires documented information to be adequate and suitable. AI-generated documentation still requires defined approval processes, which may combine automated checks with human review, appropriate to the document type and risk level." },
      { question: "An organization implements Annex A controls for AI system logging but does not define what constitutes a meaningful event to log. What is the impact?", options: ["No impact, as logging all system events provides comprehensive coverage", "Without defining meaningful events, the logs may contain excessive irrelevant data (making analysis impractical) or miss critical events (undermining monitoring), resulting in ineffective implementation of the logging control", "The logging control is conforming as long as the logging mechanism is technically functional"], correct: 1, explanation: "Effective logging requires definition of what events are meaningful for monitoring, auditing, and incident investigation. Without this definition, logging may be either overwhelming or insufficient, failing to serve its governance purpose." },
      { question: "An organization determines that AI awareness training (Clause 7.3) is needed but delivers it only once during employee onboarding. Is this sufficient?", options: ["Yes, one-time training during onboarding satisfies the awareness requirement", "Likely insufficient: awareness should be reinforced and updated as the AI policy evolves, new risks emerge, and AI systems change; a single onboarding session does not ensure ongoing awareness particularly as the AIMS and AI landscape evolve", "Yes, provided the training materials remain available for employees to reference"], correct: 1, explanation: "Clause 7.3 requires persons to be aware of the AI policy, their contribution, and implications of non-conformity. As these elements evolve, awareness must be maintained through ongoing communication, not just initial training." },

      // Domain 5 – Monitoring (3 more to reach 10 with scenarios)
      { question: "An internal auditor discovers that the organization's AI risk assessment has not been reviewed since initial implementation eighteen months ago, despite two new AI systems being deployed. How should this finding be classified?", options: ["Observation, recommending the risk assessment be updated at the next scheduled review", "Nonconformity against Clause 8.2, which requires AI risk assessment at planned intervals or when significant changes occur; deploying new AI systems constitutes a significant change that should have triggered a risk assessment update", "Opportunity for improvement, as the existing risk assessment may still adequately cover the new systems"], correct: 1, explanation: "Clause 8.2 requires AI risk assessment at planned intervals and when significant changes are proposed or occur. Deploying new AI systems is a significant change that necessitates risk assessment updates. Failure to do so is a nonconformity." },
      { question: "Management review outputs should include decisions related to continual improvement opportunities. The management review minutes list 'continue current approach' for all agenda items. What should the auditor investigate?", options: ["Nothing; management has reviewed and decided no changes are needed", "Whether the management review genuinely evaluated improvement opportunities and whether 'continue current approach' is justified by evidence, or whether it indicates a perfunctory review that fails to satisfy Clause 9.3 requirements for meaningful review and improvement decisions", "Whether the minutes accurately reflect what was discussed, as the actual discussion may have been more substantive"], correct: 1, explanation: "Clause 9.3 requires management review to include decisions on improvement opportunities. A blanket 'continue current approach' across all items raises concerns about whether the review meaningfully evaluated AIMS performance and improvement needs." },
      { question: "An organization monitors AI model performance using only the same test dataset used during initial validation. What Clause 9.1 concern does this raise?", options: ["No concern; consistent use of the same test dataset ensures comparability of metrics over time", "The monitoring approach may not detect performance degradation on real-world data that differs from the test dataset; effective monitoring should include evaluation against production data, emerging data patterns, and evolving population characteristics", "The test dataset should only be updated if model accuracy drops below an established threshold"], correct: 1, explanation: "Monitoring with only the original test dataset may miss performance issues that emerge with real-world data distribution changes. Effective Clause 9.1 monitoring should assess actual production performance, not just benchmark against static test data." },

      // Domain 6 – Improvement & certification (2 more to reach 10 with scenarios)
      { question: "A certification body identifies that one of its auditors has a financial interest in a company that provides AI consulting services to a client being audited. What must the certification body do under ISO/IEC 17021-1?", options: ["Allow the auditor to proceed if the financial interest is below a defined monetary threshold", "Remove the auditor from the audit team to address the self-interest threat to impartiality, and evaluate whether the identified conflict affects any previous audits conducted by this auditor for the same client", "Disclose the conflict to the client and proceed if the client consents"], correct: 1, explanation: "ISO/IEC 17021-1 requires certification bodies to manage impartiality threats. A financial interest in a consulting company serving the client creates a self-interest threat that must be resolved by removing the auditor, and prior audit validity should be reviewed." },
      { question: "An organization receives a major nonconformity during a surveillance audit. It submits a corrective action plan within the required timeframe. What must the certification body verify before closing the finding?", options: ["Only that the corrective action plan was submitted on time and addresses the finding", "That the root cause was properly identified, the corrective action has been effectively implemented (not just planned), and there is evidence that the action prevents recurrence of the nonconformity", "That the organization has committed to addressing the finding by the next surveillance audit"], correct: 1, explanation: "Verification of corrective action requires evidence of effective implementation and recurrence prevention, not just submission of a plan or commitment. The certification body must verify actual resolution, not planned resolution." },

      // Additional questions for domain balance
      { question: "An organization discovers a nonconformity in its AIMS but determines the root cause originated from a third-party AI vendor's actions. Under Clause 10.1, what is the organization's responsibility?", options: ["No corrective action is needed since the root cause is external and outside the organization's control", "The organization must still address the nonconformity, which may include implementing controls to manage the third-party risk, modifying vendor agreements, or adjusting oversight processes to prevent recurrence from external sources", "Transfer the nonconformity to the vendor and document the transfer in the corrective action log"], correct: 1, explanation: "Clause 10.1 requires the organization to address nonconformities regardless of their origin. External root causes do not eliminate the organization's obligation to implement corrective actions, which may include strengthening vendor management and oversight." },
      { question: "An AI system deployed within the AIMS scope begins producing outputs that are technically accurate but culturally inappropriate for certain user groups. The system has not changed, but the user population has expanded. What AIMS process should be triggered?", options: ["No process is triggered since the system is functioning as designed and accuracy is maintained", "The change in user population represents a change in context (Clause 4.1) that should trigger risk reassessment (Clause 8.2), impact assessment review (Clause 8.4), and potential updates to operational controls and monitoring criteria", "Only the communication process (Clause 7.4) needs updating to inform new user groups of potential limitations"], correct: 1, explanation: "A change in the user population changes the AI system's context and impact profile. This triggers multiple AIMS processes including context review, risk reassessment, and impact assessment, not just communication updates." },
      { question: "ISO/IEC 23053 provides a framework for AI systems using machine learning. How does this framework complement ISO/IEC 42001 implementation?", options: ["ISO/IEC 23053 replaces the need for Annex A controls related to ML systems", "ISO/IEC 23053 provides a structured description of ML system components and data flows, which helps organizations identify where AIMS controls should be applied within their ML pipelines and architecture", "ISO/IEC 23053 is only relevant for organizations seeking certification against both standards simultaneously"], correct: 1, explanation: "ISO/IEC 23053's framework for describing ML systems helps organizations understand their ML architecture systematically, enabling more effective placement of AIMS controls throughout the ML pipeline. It complements but does not replace ISO/IEC 42001 controls." },
      { question: "An organization implements an AI monitoring dashboard that shows real-time model performance metrics. During an audit, the auditor asks who reviews the dashboard and how anomalies are escalated. The organization cannot answer. What Clause 9.1 element is missing?", options: ["Nothing is missing; having the dashboard demonstrates adequate monitoring implementation", "The organization has implemented the monitoring tool but has not established the methods, responsibilities, and timing for analysis and evaluation, which are required by Clause 9.1 alongside the monitoring mechanism itself", "The only missing element is documentation of the dashboard's technical specifications"], correct: 1, explanation: "Clause 9.1 requires not just monitoring mechanisms but also defined methods for analysis and evaluation, assigned responsibilities, and established timing. A dashboard without review processes, escalation procedures, and assigned reviewers is incomplete." },
      { question: "During a recertification audit, the audit team discovers the organization has replaced all its AI systems with newer versions since the initial certification. Should the recertification treat this as a continuation of the existing certificate?", options: ["Yes, the AIMS certification covers the management system, not specific AI systems, so system replacements are irrelevant", "The audit team should verify that the AIMS processes were properly applied to the new systems, including risk assessment, impact assessment, change management, and SoA updates; if these processes functioned correctly, it demonstrates AIMS effectiveness", "No, complete system replacement requires a new initial certification since the certified systems no longer exist"], correct: 1, explanation: "Recertification evaluates the management system's effectiveness. If the organization properly managed the system transitions through AIMS processes, this demonstrates the AIMS is functioning as intended. The focus is on whether governance processes worked, not on specific system continuity." }
    ]}
  ]
};
